INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('c11d2e3f-8a4b-4c5d-9e6f-7a8b9c0d1e2f', 'gn', 1, 26, NULL, 'João Calvino', 'A criação do homem à imagem de Deus é o ápice da criação. Calvino observa que o homem recebeu domínio sobre todas as criaturas como representante de Deus. A imagem divina consiste em justiça, santidade e verdade. Aplicação: Honre a imagem de Deus em cada pessoa; exerça seu domínio com responsabilidade.', 'João Calvino', 'commentary', '#1E3A8A', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('d22e3f4a-9b5c-4d6e-8f7g-9h0i1j2k3l4m', 'gn', 2, 18, NULL, 'John Owen', 'O auxiliar adequado para o homem é providência divina. Owen destaca que a solução para a solidão do homem é de Deus, não do homem. O casamento reflete a comunhão entre Cristo e a Igreja. Aplicação: Busque em Deus a cura para a solidão; honre o casamento como instituição divina.', 'John Owen', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('e33f4a5b-0c6d-5e7f-9g8h-1i2j3k4l5m6n', 'gn', 3, 15, NULL, 'João Calvino', 'A promessa da semente que esmagará a cabeça da serpente é o evangelho primeira. Calvino chama isto de "proto-evangelho" - a primeira proclamação de redenção. Cristo venceu Satanás na cruz. Aplicação: Confie na vitória de Cristo sobre o pecado e Satanás.', 'João Calvino', 'commentary', '#1E3A8A', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('f44a5b6c-1d7e-6f8g-0h9i-2j3k4l5m6n7o', 'gn', 4, 7, NULL, 'Augusto de Hipona', 'Deus advertente: o pecado está à porta desejando a Caim, mas ele deve dominá-lo. Agostino vê aqui a graça divina oferecida antes do crime. O homem é responsável por suas escolhas. Aplicação: Reconheça a graça de Deus que o chama ao arrependimento; domine o pecado pela fé.', 'Agostinho de Hipona', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('g55b6c7d-2e8f-7g9h-1i0j-3k4l5m6n7o8p', 'gn', 6, 8, NULL, 'Martinho Lutero', 'Noé achou graça aos olhos de Deus em meio à geração perversa. Lutero enfatiza que a graça precede a fé; Deus escolhe quem salvar. A justiça de Noé foi fruto da fé. Aplicação: A graça de Deus é o fundamento de nossa salvação; viva em fé obediente.', 'Martinho Lutero', 'commentary', '#7C2D12', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('h66c7d8e-3f9g-8h0i-2j1k-4l5m6n7o8p9q', 'gn', 9, 13, NULL, 'John Bunyan', 'O arco-íris é sinal de aliança entre Deus e toda carne. Bunyan vê aqui a promessa de Deus de preservar a humanidade. O sinal aponta para Cristo, nossa paz. Aplicação: Lembre-se da fidelidade de Deus em cada tempestade; a aliança de Deus é eterna.', 'John Bunyan', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('i77d8e9f-4g0h-9i1j-3k2l-5m6n7o8p9q0r', 'gn', 12, 1, NULL, 'Thomas Watson', 'Abram sai de Ur por fé, obedecendo ao chamado divino. Watson observa que a fé opera mediante obras. Deus chama em separação do mundo. Aplicação: Obedeça à voz de Deus ainda quando o caminho parece incerto; a fé separa-se do mundo.', 'Thomas Watson', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('j88e9f0g-5h1i-0j2k-4l3m-6n7o8p9q0r1s', 'gn', 15, 6, NULL, 'João Calvino', 'Abram creu no Senhor e foi-lhe imputado como justiça. Calvino chama isto de justificação pela fé, antes da circuncisão. A promessa precede a lei. Aplicação: A justiça vem somente pela fé em Cristo; nenhuma obra merece a salvação.', 'João Calvino', 'commentary', '#1E3A8A', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('k99f0g1h-6i2j-1k3l-5m4n-7o8p9q0r1s2t', 'gn', 18, 25, NULL, 'Augusto de Hipona', 'Será que o Juiz de toda a terra não fará justiça? Agostino vê a intercessão de Abraão como modelo de oração. Deus é justo em todos seus juízos. Aplicação: Interceda pelos outros em oração; confie na justiça de Deus.', 'Agostinho de Hipona', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('l00g1h2i-7j3k-2l4m-6n5o-8p9q0r1s2t3u', 'gn', 22, 8, NULL, 'Martinho Lutero', 'Deus proverá para si o cordeiro do holocausto. Lutero vê aqui a fé de Abraão em providência divina. O cordeiro substituto prefigura Cristo. Aplicação: Confie que Deus proverá em cada provação; Cristo é nosso substituto.', 'Martinho Lutero', 'commentary', '#7C2D12', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('m11h2i3j-8k4l-3m5n-7o6p-9q0r1s2t3u4v', 'gn', 28, 15, NULL, 'Jerônimo', 'Eis que estou contigo e te guardarei por onde quer que fores. Jerônimo destaca a presença divina prometida a Jacó. Deus não abandona seus eleitos. Aplicação: Descanse na presença de Deus em cada jornada; Ele guarda seus filhos.', 'Jerônimo', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('n22i3j4k-9l5m-4n6o-8p7q-0r1s2t3u4v5w', 'gn', 32, 28, NULL, 'João Calvino', 'Teu nome não será mais Jacó, mas Israel. Calvino interpreta isto como transformação pela luta. Israel significa "príncipe com Deus". Aplicação: Busque a Deus em luta espiritual; a transformação vem mediante a luta da fé.', 'João Calvino', 'commentary', '#1E3A8A', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('o33j4k5l-0m6n-5o7p-9q8r-1s2t3u4v5w6x', 'gn', 39, 9, NULL, 'Thomas Watson', 'Como, pois, faria eu este grande mal e pecaria contra Deus? Watson vê a consciência de José nutrida pela meditação da Escritura. A graça fortalece contra tentação. Aplicação: Fortaleça sua consciência com a Palavra; nenhuma tentação vale o pecado.', 'Thomas Watson', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('p44k5l6m-1n7o-6p8q-0r9s-2t3u4v5w6x7y', 'gn', 45, 5, NULL, 'John Bunyan', 'Não vos entristeçais nem vos indignieis convosco mesmos. Bunyan enfatiza o perdão fraternal. Deus transforma o mal em bem para seus eleitos. Aplicação: Perdoe como Deus perdoou; confie no propósito soberano de Deus até no mal.', 'John Bunyan', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('q55l6m7n-2o8p-7q9r-1s0t-3u4v5w6x7y8z', 'gn', 50, 20, NULL, 'John Owen', 'Vós pensastes mal contra mim, mas Deus encaminhou para bem. Owen vê a providência divina governando intenções humanas. Deus usa até o mal para bem de seus filhos. Aplicação: Descanse na providência de Deus; Ele transforma o mal em bem.', 'John Owen', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('r66m7n8o-3p9q-8r0s-2t1u-4v5w6x7y8z9a', 'ex', 3, 14, NULL, 'João Calvino', 'Eu sou o que sou - o nome divino revelado a Moisés. Calvino vê aqui a autoexistência de Deus e sua fidelidade à aliança. Deus é independente e eterno. Aplicação: Confie no Deus que nunca muda; Ele é fiel às suas promessas.', 'João Calvino', 'commentary', '#1E3A8A', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('s77n8o9p-4q0r-9s1t-3u2v-5w6x7y8z9a0b', 'ex', 12, 13, NULL, 'Martinho Lutero', 'O sangue será sinal para vós nas casas onde estiverdes. Lutero interpreta a páscoa como figura de Cristo. O sangue protege da ira divina. Aplicação: Aplique o sangue de Cristo pela fé; somente Ele protege do juízo.', 'Martinho Lutero', 'commentary', '#7C2D12', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('t88o9p0q-5r1s-0t2u-4v3w-6x7y8z9a0b1c', 'ex', 14, 14, NULL, 'Charles Spurgeon', 'O Senhor pelejará por vós, e vos acautelareis. Spurgeon vê aqui a divisão entre ação divina e humana. Deus luta; nós descansamos. Aplicação: Descanse no poder de Deus que peleja por você; seja quieto e confie.', 'Charles Spurgeon', 'commentary', '#9333EA', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('u99p0q1r-6s2t-1u3v-5w4x-7y8z9a0b1c2d', 'ex', 19, 5, NULL, 'Thomas Watson', 'Agora, pois, se diligentemente ouvirdes a minha voz, sereis minha propriedade peculiar. Watson vê a aliança condicionada à obediência. Israel é eleito entre todos os povos. Aplicação: Obediência é fruto de eleição; viva como propriedade de Deus.', 'Thomas Watson', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('v00q1r2s-7t3u-2v4w-6x5y-8z9a0b1c2d3e', 'ex', 20, 3, NULL, 'João Calvino', 'Não terás outros deuses diante de mim - o primeiro mandamento. Calvino explica que todo bem-aventurança está em conhecer o único Deus. A idolatria é inimigo da alma. Aplicação: Coloque Deus absolutamente primeiro; rejeite todo ídolo do coração.', 'João Calvino', 'commentary', '#1E3A8A', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('w11r2s3t-8u4v-3w5x-7y6z-9a0b1c2d3e4f', 'ex', 24, 8, NULL, 'Augusto de Hipona', 'Este é o sangue da aliança que o Senhor fez convosco. Agostino vê aqui o fundamento do pacto. O sangue selava a aliança antiga. Aplicação: Cristo derramou seu sangue para selar a nova aliança; seja fiel à aliança.', 'Agostinho de Hipona', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('x22s3t4u-9v5w-4x6y-8z7a-0b1c2d3e4f5g', 'ex', 33, 15, NULL, 'John Owen', 'Se a tua presença não for conosco, não nos faças subir daqui. Owen destaca a necessidade da presença divina. Tudo é vazio sem Deus. Aplicação: Busque primeiro a presença de Deus; sem Ele, nada tem valor.', 'John Owen', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('y33t4u5v-0w6x-5y7z-9a8b-1c2d3e4f5g6h', 'ex', 34, 6, NULL, 'John Bunyan', 'O Senhor, Deus compassivo e clemente. Bunyan medita nos atributos divinos revelados. Deus é misericordioso mas justo. Aplicação: Aproxime-se de Deus com confiança e temor; Ele é compassivo mas não deixa impune.', 'John Bunyan', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('z44u5v6w-1x7y-6z8a-0b9c-2d3e4f5g6h7i', 'ex', 40, 35, NULL, 'Thomas Watson', 'A glória do Senhor encheu o tabernáculo. Watson vê a presença divina habitando entre o povo. A nuvem guiava e protegia. Aplicação: Deseje a presença gloriosa de Deus; seja guiado por sua nuvem.', 'Thomas Watson', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('a55v6w7x-2y8z-7a9b-1c0d-3e4f5g6h7i8j', 'lv', 1, 3, NULL, 'João Calvino', 'Oferecerá voluntariamente - o sacrifício é oferta voluntária. Calvino vê aqui a disposição do coração agradando a Deus. A vontade é essencial no culto. Aplicação: Ofereça-se a Deus voluntariamente; coação não agrada a Deus.', 'João Calvino', 'commentary', '#1E3A8A', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('b66w7x8y-3z9a-8b0c-2d1e-4f5g6h7i8j9k', 'lv', 4, 20, NULL, 'John Owen', 'O sacerdote fará expiação por ele, e ele será perdoado. Owen vê a necessidade de expiação para perdão. O sangue é requerido pela justiça. Aplicação: Confie na expiação de Cristo; somente sangue limpa o pecado.', 'John Owen', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('c77x8y9z-4a0b-9c1d-3e2f-5g6h7i8j9k0l', 'lv', 11, 44, NULL, 'Thomas Watson', 'Santificai-vos e sede santos, pois Eu sou santo. Watson destaca a imitação de Deus como base da santidade. A santidade é separação para Deus. Aplicação: Busque santidade que imita a Deus; seja separado para o Senhor.', 'Thomas Watson', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('d88y9z0a-5b1c-0d2e-4f3g-6h7i8j9k0l1m', 'lv', 16, 21, NULL, 'John Bunyan', 'Aaron confessará sobre a cabeça do bode. Bunyan vê a figura da transferência do pecado. O bode emissário carrega os pecados para o deserto. Aplicação: Cristo carregou nossos pecados; confesse e descanse no perdão.', 'John Bunyan', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('e99z0a1b-6c2d-1e3f-5g4h-7i8j9k0l1m2n', 'lv', 17, 11, NULL, 'Martinho Lutero', 'A vida da carne está no sangue. Lutero interpreta isto como fundamento da expiação. O sangue dado purifica o pecador. Aplicação: Valorize o sangue de Cristo derramado; nele está a vida.', 'Martinho Lutero', 'commentary', '#7C2D12', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('f00a1b2c-7d3e-2f4g-6h5i-8j9k0l1m2n3o', 'lv', 19, 2, NULL, 'João Calvino', 'Sede santos, porque Eu, o Senhor vosso Deus, sou santo. Calvino vê aqui a motivação para santidade. A lei moral é baseada no caráter de Deus. Aplicação: A santidade é obrigação e privilégio; imite seu santo Deus.', 'João Calvino', 'commentary', '#1E3A8A', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('g11b2c3d-8e4f-3g5h-7i6j-9k0l1m2n3o4p', 'lv', 19, 18, NULL, 'Augusto de Hipona', 'Amarás o teu próximo como a ti mesmo. Agostino chama isto de sumário da lei. O amor ao próximo flui do amor a Deus. Aplicação: Ame o próximo como a si mesmo; tal amor cumpre a lei.', 'Agostinho de Hipona', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('h22c3d4e-9f5g-4h6i-8j7k-0l1m2n3o4p5q', 'lv', 20, 26, NULL, 'John Wesley', 'Sede santos para mim, porque Eu, o Senhor, sou santo. Wesley conecta santidade a separação. O povo de Deus é distinto do mundo. Aplicação: Viva separado do mundo para santidade; seja distinto como Deus é distinto.', 'John Wesley', 'commentary', '#059669', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('i33d4e5f-0g6h-5i7j-9k8l-1m2n3o4p5q6r', 'lv', 25, 10, NULL, 'Jerônimo', 'Santificarás o ano cinqüentésimo. Jerônimo vê o jubileu como restauração divina. A liberdade e a terra retornam. Aplicação: Cristo é nosso jubileu; nEle há liberdade verdadeira e restauração.', 'Jerônimo', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('j44e5f6g-1h7i-6j8k-0l9m-2n3o4p5q6r7s', 'nm', 6, 24, NULL, 'John Owen', 'O Senhor te abençoe e te guarde. Owen medita na bênção sacerdotal. Três aspectos da graça divina: bênção, proteção, paz. Aplicação: Receba a bênção sacerdotal em Cristo; Ele é nosso grande Sumo Sacerdote.', 'John Owen', 'commentary', '#065F46', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('k55f6g7h-2i8j-7k9l-1m0n-3o4p5q6r7s8t', 'nm', 11, 29, 'Moisés respondeu: Está o Senhor com inveja por mim? Quem dera que todo o povo do Senhor fosse profeta. Calvino vê aqui o desejo de Moisés pela universalidade do dom. O Espírito é derramado abundantemente. Aplicação: Deseje e busque o dom do Espírito; todos os crentes são profetas em Cristo.', 'nm', 13, 30, NULL, 'Thomas Watson', 'Calebe fez sossegar o povo. Watson destaca a fé contra o medo. A coragem nascida da fé vence obstáculos. Aplicação: Seja corajoso pela fé; a terra prometida é boa, conquiste-a.', 'João Calvino', 'commentary', '#1E3A8A', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('l66g7h8i-3j9k-8l0m-2n1o-4p5q6r7s8t9u', 'nm', 14, 24, NULL, 'Martinho Lutero', 'Mas o meu servo Calebe, porquanto nele houve outro espírito. Lutero vê a diferença entre fé e incredulidade. Calebe seguiu o Senhor de todo o coração. Aplicação: Tenha outro espírito de fé; siga o Senhor de coração inteiro.', 'Martinho Lutero', 'commentary', '#7C2D12', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('m77h8i9j-4k0l-9m1n-3o2p-5q6r7s8t9u0v', 'nm', 21, 8, NULL, 'John Bunyan', 'Fez Moisés uma serpente de metal. Bunyan interpreta a serpente levantada como figura de Cristo. Olhar para a serpente curava. Aplicação: Olhe para Cristo levantado na cruz; pela fé receba cura do veneno do pecado.', 'John Bunyan', 'commentary', '#B8860B', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('n88i9j0k-5l1m-0n2o-4p3q-6r7s8t9u0v1w', 'nm', 23, 19, NULL, 'Charles Spurgeon', 'Deus não é homem, para que minta. Spurgeon medita na imutabilidade divina. As promessas de Deus são certas. Aplicação: Descanse na imutabilidade de Deus; suas promessas são eternas.', 'Charles Spurgeon', 'commentary', '#9333EA', NOW());
INSERT INTO public.study_notes (id, book_id, chapter, verse_start, verse_end, title, content, source, note_type, color, created_at) VALUES ('o99j0k1l-6m2n-1o3p-5q4r-7s8t9u0v1w2x', 'nm', 32, 23, NULL, 'João Calvino', 'Tudo o que tiveram, pecarão contra mim. Calvino vê a consequência da idolatria. O pecado afeta toda a congregação. Aplicação: Guarde-se da idolatria; o pecado tem consequências coletivas.', 'João Calvino', 'commentary', '#1E3A8A', NOW());
